// Push Chicago, Austin, SLC all to 400+
const fs = require('fs');
let html = fs.readFileSync('index.html','utf8');

function findArray(html, marker) {
  const pos = html.indexOf(marker);
  if (pos === -1) return null;
  const arrS = html.indexOf('[', pos);
  let d=0, arrE=arrS;
  for(let j=arrS;j<html.length;j++){if(html[j]==='[')d++;if(html[j]===']'){d--;if(d===0){arrE=j+1;break;}}}
  return {arrS, arrE, arr: JSON.parse(html.substring(arrS, arrE))};
}

function processCity(cityName, marker) {
  const result = findArray(html, marker);
  if (!result) { console.log(cityName + ' NOT FOUND'); return; }
  let {arrS, arrE, arr} = result;
  console.log(cityName + ' starting:', arr.length);
  const maxId = Math.max(...arr.map(r=>r.id));
  let nextId = maxId + 1;
  const existing = new Set(arr.map(r=>r.name.toLowerCase()));
  let added = 0;

  function add(s){
    if(existing.has(s.name.toLowerCase())) return;
    s.id=nextId++;s.bestOf=[];s.busyness=null;s.waitTime=null;s.popularTimes=null;s.lastUpdated=null;s.trending=s.trending||false;s.group=s.group||'';s.suburb=s.suburb||false;s.menuUrl='';s.res_tier=s.price>=3?4:2;s.indicators=s.indicators||[];s.awards=s.awards||'';s.phone=s.phone||'';s.reserveUrl=s.reserveUrl||'';s.hh=s.hh||'';s.verified=true;
    arr.push(s);existing.add(s.name.toLowerCase());added++;
  }

  return {arrS, arrE, arr, add, getAdded: ()=>added};
}

// ========== CHICAGO (needs ~58) ==========
const chiMarker = "'Chicago':";
const cdStart = html.indexOf('CITY_DATA');
const chiSearch = html.indexOf(chiMarker, cdStart);
const chiArrS = html.indexOf('[', chiSearch);
let cd=0, chiArrE=chiArrS;
for(let j=chiArrS;j<html.length;j++){if(html[j]==='[')cd++;if(html[j]===']'){cd--;if(cd===0){chiArrE=j+1;break;}}}
let chiArr = JSON.parse(html.substring(chiArrS, chiArrE));
console.log('Chicago starting:', chiArr.length);
let chiMaxId = Math.max(...chiArr.map(r=>r.id));
let chiNextId = chiMaxId + 1;
const chiExisting = new Set(chiArr.map(r=>r.name.toLowerCase()));
let chiAdded = 0;
function chiAdd(s){
  if(chiExisting.has(s.name.toLowerCase())) return;
  s.id=chiNextId++;s.bestOf=[];s.busyness=null;s.waitTime=null;s.popularTimes=null;s.lastUpdated=null;s.trending=s.trending||false;s.group=s.group||'';s.suburb=s.suburb||false;s.menuUrl='';s.res_tier=s.price>=3?4:2;s.indicators=s.indicators||[];s.awards=s.awards||'';s.phone=s.phone||'';s.reserveUrl=s.reserveUrl||'';s.hh=s.hh||'';s.verified=true;
  chiArr.push(s);chiExisting.add(s.name.toLowerCase());chiAdded++;
}

